func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	assignCount := dispatch.AssignsLen
	const BIGCOST = 1e9
	type candInfo struct {
		idx     int
		costInc float64
		posOri  int
		posDes  int
	}
	safeSeedIdx := assignCount
	if safeSeedIdx >= MAXASSIGNS {
		safeSeedIdx = 0
	}
	for oi := 0; oi < orderCount; oi++ {
		id := total_ship + oi
		bestCands := make([]candInfo, 0, assignCount+1)
		for ai := 0; ai < assignCount; ai++ {
			oldCost := dispatch.Assigns[ai].Cost
			if oldCost < 0 {
				continue
			}
			if !dispatch.Assigns[ai].AddShip(id, oris[oi], dess[oi]) {
				continue
			}
			newCost := dispatch.Assigns[ai].Cost
			if newCost < 0 {
				dispatch.Assigns[ai].RemoveShip(id)
				dispatch.Assigns[ai].GenRoute()
				continue
			}
			inc := newCost - oldCost
			if inc >= 0 && inc < BIGCOST {
				bestCands = append(bestCands, candInfo{idx: ai, costInc: inc})
			}
			dispatch.Assigns[ai].RemoveShip(id)
			dispatch.Assigns[ai].GenRoute()
		}
		if len(bestCands) == 0 {
			if safeSeedIdx < MAXASSIGNS && safeSeedIdx <= dispatch.AssignsLen {
				addOk := false
				if safeSeedIdx == dispatch.AssignsLen {
					tempAsgn := &dispatch.Assigns[safeSeedIdx]
					tempAsgn.AddShip(id, oris[oi], dess[oi])
					tempAsgn.GenRoute()
					if tempAsgn.Cost >= 0 {
						dispatch.AssignsLen++
						addOk = true
					} else {
						tempAsgn.RemoveShip(id)
						tempAsgn.GenRoute()
					}
				} else if safeSeedIdx < dispatch.AssignsLen {
					addOk = dispatch.Assigns[safeSeedIdx].AddShip(id, oris[oi], dess[oi])
					if addOk {
						dispatch.Assigns[safeSeedIdx].GenRoute()
						if dispatch.Assigns[safeSeedIdx].Cost < 0 {
							dispatch.Assigns[safeSeedIdx].RemoveShip(id)
							dispatch.Assigns[safeSeedIdx].GenRoute()
