							asgn.GenRoute()
							if asgn.Cost >= 0 {
								if fi >= dispatch.AssignsLen {
									dispatch.AssignsLen = fi + 1
								}
								break
							}
							asgn.RemoveShip(id)
							asgn.GenRoute()
						}
					}
				}
			}
