				copied := dispatch.Assigns[ai]
				ok := copied.AddShip(orderId, ori, des)
				if ok {
					copied.GenRoute()
					if copied.Cost >= 0 {
						added = true
						tmpCost = copied.Cost
					}
				}
			} else {
				if nextEmptyIdx < MAXASSIGNS {
					emptyAssign := dispatch.Assigns[nextEmptyIdx]
					ok := emptyAssign.AddShip(orderId, ori, des)
					if ok {
						emptyAssign.GenRoute()
						if emptyAssign.Cost >= 0 {
							added = true
							tmpCost = emptyAssign.Cost
						}
					}
				}
			}
			if added {
				baseCost := tmpCost
				slackPenalty := 0.0
				timeSlack := float64(des.TimeEnd-des.TimeStart) / 60.0
				if timeSlack <= 10 {
					slackPenalty += 50.0 * (11.0 - timeSlack)
				}
				loadRatio := float64(ori.Load+des.Load) / 100.0
				if loadRatio > 0.8 {
					slackPenalty += 30.0 * (loadRatio - 0.8)
				}
				score := baseCost + slackPenalty
				if bestAi == -1 || score < bestScore {
					bestScore = score
					bestAi = ai
				}
				if ai < assignsCap {
					dispatch.Assigns[ai].RemoveShip(orderId)
					dispatch.Assigns[ai].GenRoute()
				}
			}
		}
		insertOk := false
		if bestAi >= 0 && bestAi < assignsCap {
			ok := dispatch.Assigns[bestAi].AddShip(orderId, ori, des)
			if ok {
				dispatch.Assigns[bestAi].GenRoute()
				if dispatch.Assigns[bestAi].Cost >= 0 {
					insertOk = true
				} else {
					dispatch.Assigns[bestAi].RemoveShip(orderId)
					dispatch.Assigns[bestAi].GenRoute()
				}
			}
		}
		if !insertOk {
			fallbackAi := nextEmptyIdx
			if fallbackAi < MAXASSIGNS {
				ok := dispatch.Assigns[fallbackAi].AddShip(orderId, ori, des)
				if ok {
					dispatch.Assigns[fallbackAi].GenRoute()
					if dispatch.Assigns[fallbackAi].Cost >= 0 {
						insertOk = true
						if fallbackAi >= dispatch.AssignsLen {
							dispatch.AssignsLen = fallbackAi + 1
						}
						nextEmptyIdx = fallbackAi + 1
					} else {
						dispatch.Assigns[fallbackAi].RemoveShip(orderId)
						dispatch.Assigns[fallbackAi].GenRoute()
					}
				}
			}
			if !insertOk && assignsCap < MAXASSIGNS {
				ok := dispatch.Assigns[assignsCap].AddShip(orderId, ori, des)
				if ok {
					dispatch.Assigns[assignsCap].GenRoute()
					if dispatch.Assigns[assignsCap].Cost >= 0 {
						insertOk = true
						if assignsCap >= dispatch.AssignsLen {
							dispatch.AssignsLen = assignsCap + 1
						}
						nextEmptyIdx = assignsCap + 1
					} else {
						dispatch.Assigns[assignsCap].RemoveShip(orderId)
						dispatch.Assigns[assignsCap].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
